{
  "questions": [
    {
      "format": "sortOrder",
      "question": "A user types a URL and presses Enter. Put the stages of fetching and showing the page in the order the browser actually processes them.",
      "items": [
        "Resolve the domain name to an IP address",
        "Open a TCP connection and complete the TLS handshake",
        "Send the HTTP request to the server",
        "Receive the server's HTTP response",
        "Parse the HTML and build the page",
        "Render the visible page"
      ],
      "feedback": "The browser needs an IP before it can connect, a connection before it can send a request, and a response before it can parse and render. Each step depends on the one before it."
    },
    {
      "format": "multipleChoice",
      "context": "A page loads but one image is broken. In the Network panel, the image request shows a 404 status code while everything else is 200.",
      "question": "What does the 404 tell you?",
      "options": [
        {
          "feedback": "A 404 means the server was reached fine, so the connection and DNS worked.",
          "isCorrect": false,
          "text": "The DNS lookup for the image failed"
        },
        {
          "feedback": "Right. The server responded, but it couldn't find a resource at that path, so the URL or file location is wrong.",
          "isCorrect": true,
          "text": "The server responded but couldn't find that resource"
        },
        {
          "feedback": "A timeout would show no response or a pending/failed state, not a clean 404.",
          "isCorrect": false,
          "text": "The request timed out before reaching the server"
        },
        {
          "feedback": "A 404 is a clear server response, not a TLS problem, which would block the connection entirely.",
          "isCorrect": false,
          "text": "The TLS handshake was rejected"
        }
      ]
    },
    {
      "format": "matchColumns",
      "pairs": [
        {
          "left": "Browser console shows 'blocked by CORS policy'",
          "right": "Server didn't send the right Access-Control-Allow-Origin header"
        },
        {
          "left": "Response status is 401",
          "right": "Missing or invalid authentication credentials"
        },
        {
          "left": "Request stays pending then fails after 30 seconds",
          "right": "Server never responded in time (timeout)"
        },
        {
          "left": "Response is 304 and content looks stale",
          "right": "Browser served or revalidated a cached copy"
        },
        {
          "left": "Status 301 sends the browser to a new URL",
          "right": "A redirect pointing the request elsewhere"
        }
      ],
      "question": "Match each piece of evidence to the failure it points to."
    },
    {
      "format": "multipleChoice",
      "context": "An API call returns 200, but the browser console says the response was 'blocked by CORS policy: No Access-Control-Allow-Origin header'.",
      "question": "Where should the fix happen?",
      "options": [
        {
          "feedback": "The browser enforces CORS but doesn't grant permission; it only checks the server's headers.",
          "isCorrect": false,
          "text": "Change a browser setting to ignore the policy"
        },
        {
          "feedback": "Correct. CORS permission comes from the server's response headers, so the server must include the allow-origin header for that origin.",
          "isCorrect": true,
          "text": "Configure the server to send the proper allow-origin header"
        },
        {
          "feedback": "A 200 means authentication passed; the block is about cross-origin permission, not credentials.",
          "isCorrect": false,
          "text": "Add a password to the request"
        },
        {
          "feedback": "DNS already resolved since the request reached the server and returned 200.",
          "isCorrect": false,
          "text": "Fix the DNS record for the API domain"
        }
      ]
    },
    {
      "format": "fillBlank",
      "question": "Complete the sentence about reading status codes during debugging.",
      "template": "A status code in the [BLANK] range means the client sent something wrong, while the [BLANK] range means the server failed while handling a valid request.",
      "answers": [
        "4xx",
        "5xx"
      ],
      "distractors": [
        "2xx",
        "3xx"
      ],
      "feedback": "4xx codes (like 401 and 404) point to a client-side problem such as a bad URL or missing auth. 5xx codes (like 500 and 503) mean the server broke while processing the request."
    },
    {
      "format": "multipleChoice",
      "context": "You update a CSS file on the server, but the browser keeps showing the old styles. The Network panel shows the CSS request returning '200 (from disk cache)'.",
      "question": "What's the most likely cause?",
      "options": [
        {
          "feedback": "A redirect would show 3xx and a new location, not a cached 200.",
          "isCorrect": false,
          "text": "The server is redirecting the file request"
        },
        {
          "feedback": "Exactly. 'from disk cache' means the browser reused a stored copy instead of fetching the updated file.",
          "isCorrect": true,
          "text": "The browser is serving a cached copy of the old file"
        },
        {
          "feedback": "CORS errors block the response and log to the console; this request succeeded from cache.",
          "isCorrect": false,
          "text": "A CORS policy is blocking the new file"
        },
        {
          "feedback": "The 200 status means the resource was found, just served from cache rather than the network.",
          "isCorrect": false,
          "text": "The new file path returns a 404"
        }
      ]
    },
    {
      "format": "multipleChoice",
      "context": "A login request returns 401. You're debugging the request lifecycle in order: DNS, connection, request sent, response.",
      "question": "What does reaching a 401 confirm?",
      "options": [
        {
          "feedback": "DNS, connection, and the request all succeeded—otherwise you'd never get an HTTP status back.",
          "isCorrect": false,
          "text": "The DNS lookup is still failing"
        },
        {
          "feedback": "Correct. Getting a 401 means the full path up to a server response worked; the issue is that credentials were missing or rejected.",
          "isCorrect": true,
          "text": "The request reached the server, but authentication was rejected"
        },
        {
          "feedback": "A TLS failure would prevent any HTTP response from arriving at all.",
          "isCorrect": false,
          "text": "The TLS handshake never completed"
        },
        {
          "feedback": "A 401 is a real response, not a timeout, which would leave the request pending.",
          "isCorrect": false,
          "text": "The request timed out before the server replied"
        }
      ]
    },
    {
      "format": "selectImage",
      "question": "While debugging a slow page, you check the Network timing breakdown for one request. Which timing bar points to a slow server rather than a slow connection?",
      "options": [
        {
          "feedback": "",
          "isCorrect": true,
          "prompt": "x"
        }
      ]
    }
  ]
}

{
  "questions": [
    {
      "format": "multipleChoice",
      "context": "A team wants to know whether new users finish setting up their account. They define the funnel entry as 'app installed' and the final step as 'first project created,' counting any order within 30 days.",
      "question": "What's the main flaw in this funnel design?",
